import spectrum_utils.spectrum as sus; import spectrum_utils.utils as suu; import numpy as np; from scipy.sparse import csr_matrix; import hashlib; spectra = suu.load_spectra('{inputs.raw_spectra}'); bin_width = 0.1; n_features = 10000; hashed_vectors = []; 
for spec in spectra:
  mz, intensity = spec.mz, spec.intensity; binned = np.zeros(int((mz[-1] - mz[0]) / bin_width) + 1);
  for m, i in zip(mz, intensity):
    idx = int((m - mz[0]) / bin_width); binned[idx] += i
  binned = binned / (np.sum(binned) + 1e-10); hashed = np.zeros(n_features);
  for i, val in enumerate(binned):
    if val > 0: h = int(hashlib.md5(str(i).encode()).hexdigest(), 16) % n_features; hashed[h] += val
  hashed_vectors.append(hashed)
X = np.array(hashed_vectors); np.save('hashed_spectra_matrix.npy', X); print(f'Output shape: {X.shape}')
